# ABOUTME: MCP tools for JinaAI Reader API integration
# ABOUTME: Converts URLs to clean markdown using JinaAI Reader service
"""MCP tools for JinaAI Reader API integration."""

import httpx
from claude_agent_sdk import tool
from typing import Dict, Any

JINA_READER_BASE = "https://r.jina.ai"


@tool(
    name="fetch_markdown",
    description="Convert a URL to clean markdown using JinaAI Reader API",
    input_schema={"url": str}
)
async def fetch_markdown(args: Dict[str, Any]) -> Dict[str, Any]:
    """
    Fetch a URL and convert it to markdown using JinaAI Reader.

    Args:
        args: {"url": "https://example.com/article"}

    Returns:
        {"content": [{"type": "text", "text": "markdown content"}]}
    """
    url = args["url"]

    try:
        async with httpx.AsyncClient(timeout=30.0) as client:
            response = await client.get(
                f"{JINA_READER_BASE}/{url}",
                headers={
                    "Accept": "text/markdown",
                    "X-Return-Format": "markdown"
                }
            )
            response.raise_for_status()

            markdown = response.text

            return {
                "content": [{
                    "type": "text",
                    "text": f"Successfully fetched and converted to markdown:\n\n{markdown}"
                }]
            }

    except httpx.HTTPError as e:
        return {
            "content": [{
                "type": "text",
                "text": f"Error fetching URL: {str(e)}"
            }],
            "isError": True
        }

# ABOUTME: MCP tools for Chroma vector database integration
# ABOUTME: Stores and searches content with embeddings using Chroma DB
"""MCP tools for Chroma vector database integration."""

import chromadb
from chromadb.config import Settings
from claude_agent_sdk import tool
from typing import Dict, Any, List, Optional

# Initialize Chroma client (singleton)
_chroma_client: Optional[chromadb.Client] = None


def get_chroma_client() -> chromadb.Client:
    """Get or create singleton Chroma client."""
    global _chroma_client
    if _chroma_client is None:
        _chroma_client = chromadb.Client(Settings(
            persist_directory="./chroma_data",
            anonymized_telemetry=False
        ))
    return _chroma_client


@tool(
    name="store_content",
    description="Store content in Chroma vector database with embeddings",
    input_schema={
        "content_id": str,
        "text": str,
        "metadata": dict
    }
)
async def store_content(args: Dict[str, Any]) -> Dict[str, Any]:
    """
    Store content in Chroma with automatic embedding generation.

    Args:
        args: {
            "content_id": "uuid-string",
            "text": "markdown content",
            "metadata": {"url": "...", "title": "..."}
        }
    """
    try:
        client = get_chroma_client()
        collection = client.get_or_create_collection(
            name="mochi_donut_content",
            metadata={"description": "Processed content for flashcard generation"}
        )

        # Store with automatic embedding
        collection.add(
            documents=[args["text"]],
            metadatas=[args["metadata"]],
            ids=[args["content_id"]]
        )

        return {
            "content": [{
                "type": "text",
                "text": f"Stored content {args['content_id']} in Chroma"
            }]
        }

    except Exception as e:
        return {
            "content": [{
                "type": "text",
                "text": f"Error storing in Chroma: {str(e)}"
            }],
            "isError": True
        }


@tool(
    name="search_similar",
    description="Search for similar content in Chroma vector database",
    input_schema={
        "query": str,
        "n_results": int
    }
)
async def search_similar(args: Dict[str, Any]) -> Dict[str, Any]:
    """
    Search for semantically similar content.

    Args:
        args: {
            "query": "search query text",
            "n_results": 5
        }
    """
    try:
        client = get_chroma_client()
        collection = client.get_collection("mochi_donut_content")

        results = collection.query(
            query_texts=[args["query"]],
            n_results=args.get("n_results", 5)
        )

        # Format results
        formatted = []
        for i, doc in enumerate(results['documents'][0]):
            metadata = results['metadatas'][0][i]
            distance = results['distances'][0][i]
            formatted.append({
                "content": doc[:200] + "...",
                "metadata": metadata,
                "similarity": 1 - distance  # Convert distance to similarity
            })

        return {
            "content": [{
                "type": "text",
                "text": f"Found {len(formatted)} similar documents:\n" +
                       "\n".join([f"- {r['metadata'].get('title', 'Untitled')} (similarity: {r['similarity']:.2f})"
                                 for r in formatted])
            }]
        }

    except Exception as e:
        return {
            "content": [{
                "type": "text",
                "text": f"Error searching Chroma: {str(e)}"
            }],
            "isError": True
        }

# ABOUTME: MCP tools for Mochi API integration
# ABOUTME: Creates flashcards and manages decks in Mochi spaced repetition app
"""MCP tools for Mochi API integration."""

import httpx
from claude_agent_sdk import tool
from typing import Dict, Any, List
import os

MOCHI_API_BASE = "https://app.mochi.cards/api"
MOCHI_API_KEY = os.getenv("MOCHI_API_KEY")


@tool(
    name="create_card",
    description="Create a flashcard in Mochi",
    input_schema={
        "deck_id": str,
        "question": str,
        "answer": str,
        "tags": list
    }
)
async def create_card(args: Dict[str, Any]) -> Dict[str, Any]:
    """
    Create a flashcard in Mochi.

    Args:
        args: {
            "deck_id": "deck-uuid",
            "question": "Front of card",
            "answer": "Back of card",
            "tags": ["tag1", "tag2"]
        }
    """
    try:
        if not MOCHI_API_KEY:
            return {
                "content": [{
                    "type": "text",
                    "text": "Error: MOCHI_API_KEY environment variable not set"
                }],
                "isError": True
            }

        async with httpx.AsyncClient() as client:
            response = await client.post(
                f"{MOCHI_API_BASE}/cards",
                headers={
                    "Authorization": f"Bearer {MOCHI_API_KEY}",
                    "Content-Type": "application/json"
                },
                json={
                    "deck-id": args["deck_id"],
                    "content": args["question"],
                    "fields": {
                        "answer": {"value": args["answer"]}
                    },
                    "tags": args.get("tags", [])
                }
            )
            response.raise_for_status()

            card = response.json()
            return {
                "content": [{
                    "type": "text",
                    "text": f"Created Mochi card: {card.get('id')}"
                }]
            }

    except httpx.HTTPError as e:
        return {
            "content": [{
                "type": "text",
                "text": f"Error creating Mochi card: {str(e)}"
            }],
            "isError": True
        }


@tool(
    name="list_decks",
    description="List all available Mochi decks",
    input_schema={}
)
async def list_decks(args: Dict[str, Any]) -> Dict[str, Any]:
    """List all Mochi decks for the user."""
    try:
        if not MOCHI_API_KEY:
            return {
                "content": [{
                    "type": "text",
                    "text": "Error: MOCHI_API_KEY environment variable not set"
                }],
                "isError": True
            }

        async with httpx.AsyncClient() as client:
            response = await client.get(
                f"{MOCHI_API_BASE}/decks",
                headers={"Authorization": f"Bearer {MOCHI_API_KEY}"}
            )
            response.raise_for_status()

            decks = response.json()
            deck_list = "\n".join([
                f"- {deck['name']} (ID: {deck['id']})"
                for deck in decks.get('docs', [])
            ])

            return {
                "content": [{
                    "type": "text",
                    "text": f"Available Mochi decks:\n{deck_list}"
                }]
            }

    except httpx.HTTPError as e:
        return {
            "content": [{
                "type": "text",
                "text": f"Error listing decks: {str(e)}"
            }],
            "isError": True
        }

# ABOUTME: MCP tools for database operations
# ABOUTME: Saves and queries content and prompts using async SQLAlchemy
"""MCP tools for database operations."""

from claude_agent_sdk import tool
from typing import Dict, Any, List
from sqlalchemy import select
from src.app.core.database import db
from src.app.db.models import Content, Prompt, QualityMetric
import uuid


@tool(
    name="save_content",
    description="Save processed content to database",
    input_schema={
        "content_id": str,
        "source_url": str,
        "markdown": str,
        "metadata": dict
    }
)
async def save_content(args: Dict[str, Any]) -> Dict[str, Any]:
    """
    Save content to database.

    Args:
        args: {
            "content_id": "uuid-string",
            "source_url": "https://...",
            "markdown": "markdown content",
            "metadata": {"title": "...", "author": "..."}
        }
    """
    try:
        async with db.async_session() as session:
            # Generate content hash from markdown
            import hashlib
            content_hash = hashlib.sha256(args["markdown"].encode()).hexdigest()

            # Extract metadata fields
            metadata = args.get("metadata", {})

            content = Content(
                id=uuid.UUID(args["content_id"]),
                source_url=args["source_url"],
                source_type="web",  # Default to web, can be parameterized
                title=metadata.get("title"),
                author=metadata.get("author"),
                markdown_content=args["markdown"],
                content_hash=content_hash,
                content_metadata=metadata,
                processing_status="completed"
            )
            session.add(content)
            await session.commit()

            return {
                "content": [{
                    "type": "text",
                    "text": f"Saved content to database: {args['content_id']}"
                }]
            }

    except Exception as e:
        return {
            "content": [{
                "type": "text",
                "text": f"Error saving content: {str(e)}"
            }],
            "isError": True
        }


@tool(
    name="save_prompts",
    description="Save generated prompts to database",
    input_schema={
        "content_id": str,
        "prompts": list  # List of prompt objects
    }
)
async def save_prompts(args: Dict[str, Any]) -> Dict[str, Any]:
    """
    Save generated prompts to database.

    Args:
        args: {
            "content_id": "uuid-string",
            "prompts": [
                {
                    "question": "...",
                    "answer": "...",
                    "prompt_type": "factual",
                    "difficulty_level": 3,
                    "confidence_score": 0.85,
                    "source_context": "..."
                }
            ]
        }
    """
    try:
        async with db.async_session() as session:
            prompt_ids = []

            for p in args["prompts"]:
                prompt = Prompt(
                    id=uuid.uuid4(),
                    content_id=uuid.UUID(args["content_id"]),
                    question=p["question"],
                    answer=p["answer"],
                    prompt_type=p["prompt_type"],
                    difficulty_level=p.get("difficulty_level"),
                    confidence_score=p.get("confidence_score"),
                    source_context=p.get("source_context")
                )
                session.add(prompt)
                prompt_ids.append(str(prompt.id))

            await session.commit()

            return {
                "content": [{
                    "type": "text",
                    "text": f"Saved {len(prompt_ids)} prompts to database"
                }]
            }

    except Exception as e:
        return {
            "content": [{
                "type": "text",
                "text": f"Error saving prompts: {str(e)}"
            }],
            "isError": True
        }


@tool(
    name="query_prompts",
    description="Query database for prompts by various criteria",
    input_schema={
        "content_id": str,
        "status": str,
        "limit": int
    }
)
async def query_prompts(args: Dict[str, Any]) -> Dict[str, Any]:
    """
    Query prompts from database.

    Args:
        args: {
            "content_id": "uuid-string" (optional),
            "status": "pending" (optional),
            "limit": 10
        }
    """
    try:
        async with db.async_session() as session:
            query = select(Prompt)

            if args.get("content_id"):
                query = query.where(Prompt.content_id == uuid.UUID(args["content_id"]))

            # Note: status filtering would require PromptStatus field
            # which isn't in the current Prompt model

            query = query.limit(args.get("limit", 10))

            result = await session.execute(query)
            prompts = result.scalars().all()

            formatted_prompts = [
                {
                    "id": str(p.id),
                    "question": p.question[:100] + "..." if len(p.question) > 100 else p.question,
                    "prompt_type": p.prompt_type.value,
                    "confidence_score": p.confidence_score
                }
                for p in prompts
            ]

            return {
                "content": [{
                    "type": "text",
                    "text": f"Found {len(prompts)} prompts:\n" +
                           "\n".join([f"- {p['question']} ({p['prompt_type']})"
                                     for p in formatted_prompts])
                }]
            }

    except Exception as e:
        return {
            "content": [{
                "type": "text",
                "text": f"Error querying prompts: {str(e)}"
            }],
            "isError": True
        }


@tool(
    name="update_prompt_status",
    description="Update the status of a prompt",
    input_schema={
        "prompt_id": str,
        "mochi_card_id": str,
        "mochi_deck_id": str
    }
)
async def update_prompt_status(args: Dict[str, Any]) -> Dict[str, Any]:
    """
    Update prompt with Mochi card information.

    Args:
        args: {
            "prompt_id": "uuid-string",
            "mochi_card_id": "mochi-card-id",
            "mochi_deck_id": "mochi-deck-id"
        }
    """
    try:
        async with db.async_session() as session:
            query = select(Prompt).where(Prompt.id == uuid.UUID(args["prompt_id"]))
            result = await session.execute(query)
            prompt = result.scalar_one_or_none()

            if not prompt:
                return {
                    "content": [{
                        "type": "text",
                        "text": f"Prompt {args['prompt_id']} not found"
                    }],
                    "isError": True
                }

            prompt.mochi_card_id = args.get("mochi_card_id")
            prompt.mochi_deck_id = args.get("mochi_deck_id")
            prompt.mochi_status = "sent"

            await session.commit()

            return {
                "content": [{
                    "type": "text",
                    "text": f"Updated prompt {args['prompt_id']} with Mochi card info"
                }]
            }

    except Exception as e:
        return {
            "content": [{
                "type": "text",
                "text": f"Error updating prompt status: {str(e)}"
            }],
            "isError": True
        }
